const row = $input.item.json;

// Normalize keys
const r = {};
for (const key of Object.keys(row)) {
  r[key.trim()] = (row[key] ?? '').toString().trim();
}

const email = r['Email Address'] || '';
if (!email) return null; // skip rows with no email

// col_18 = column R = Processed
const processedByCol = (row['col_18'] ?? '').toString().trim();
const processedByName = r['Processed'] || '';
const processed = processedByCol || processedByName;

if (processed === '1') {
  return null; // skip
}

return { json: row };

const row = $input.first().json;
const r = {};
for (const key of Object.keys(row)) { r[key.trim()] = (row[key] ?? '').toString().trim(); }

const position   = r['Select the Position You Are Applying For'] || '';
const name       = r['Full Name'] || '';
const email      = r['Email Address'] || '';
const experience = r['Years of Experience'] || '';
const skills     = r['Relevant Skills'] || '';
const rowNum      = parseInt(row['row_number']) || 0;

const JD_MAP = {
  'Frontend Developer': 'ROLE: Frontend Developer. REQUIREMENTS: 2+ years React/Vue, HTML/CSS/JavaScript.',
  'Backend Developer': 'ROLE: Backend Developer. REQUIREMENTS: 2+ years Node.js/Python, SQL/NoSQL.',
  'UI/UX Designer': 'ROLE: UI/UX Designer. REQUIREMENTS: Figma, Portfolio.',
  'Project Manager': 'ROLE: Project Manager. REQUIREMENTS: 3+ years PM experience.',
  'Digital Marketing Executive': 'ROLE: Digital Marketing Executive. REQUIREMENTS: SEO/SEM, Google Ads.'
};
const jd = JD_MAP[position] || 'General professional evaluation.';

return [{ json: { ...r, row_number: rowNum, jd } }];

const aiRaw = $input.first().json.output || '';
const fd = $('Extract Fields & Load JD').first().json;
let p = { score: 5, grade: 'Maybe' };
try { p = JSON.parse(aiRaw); } catch(e) {}
const status = p.score >= 7 ? 'Shortlisted' : 'Rejected';
return [{ json: { ...fd, ...p, status, processed_at: new Date().toISOString() } }];

const d = $input.first().json;
const rowNum = d.row_number;
const range = `Form responses 1!J${rowNum}:R${rowNum}`;
const values = [String(d.score), d.grade, d.strengths, d.weaknesses, d.recommendation, d.summary, d.status, d.processed_at, '1'];
return [{ json: { ...d, _requestBody: { range, values: [values] }, _url: `https://sheets.googleapis.com/v4/spreadsheets/1iv-8fToAzxBm8ht5vg-UP_p_hQzK4-uqs2KWu06im4o/values/${encodeURIComponent(range)}?valueInputOption=RAW` } }];
